CustomField.formula:
IF( 
AND( 
OR( 
MONTH(sugati__GM_Opportunity__r.sugati__O_Departure_Date__c)<= MONTH(sugati__GM_Contact__r.Birthdate), 
MONTH(sugati__GM_Contact__r.Birthdate)<= MONTH(sugati__GM_Opportunity__r.sugati__O_Return_Date__c) 
), 
OR( 
DAY(sugati__GM_Opportunity__r.sugati__O_Departure_Date__c)<= DAY(sugati__GM_Contact__r.Birthdate), 
DAY(sugati__GM_Contact__r.Birthdate)<= DAY(sugati__GM_Opportunity__r.sugati__O_Return_Date__c) 
) 
), 
true,false 
)
